import React, { useEffect, useState, useCallback } from 'react';
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip,
  ResponsiveContainer, Cell, RadarChart, Radar,
  PolarGrid, PolarAngleAxis, PolarRadiusAxis,
} from 'recharts';
import { adminService } from '@/services/adminService';
import type {
  AnalyticsData, AnalyticsFilters,
} from '@/services/adminService';
import './AdminAnalytics.css';
import './AdminDashboard.css';

interface AdminAnalyticsProps {
  onNavigate?: (screen: string) => void;
}

// ── Date range presets ──
const DATE_PRESETS = [
  { label: 'All Time', value: 'all' },
  { label: 'Last 7 Days', value: '7d' },
  { label: 'Last 30 Days', value: '30d' },
  { label: 'Last 90 Days', value: '90d' },
];

// ── Color palette ──
const STATUS_COLORS: Record<string, string> = {
  pending: '#6b748a',
  in_progress: '#5b8cff',
  submitted: '#f5c542',
  completed: '#43e8b0',
  overdue: '#ff6b6b',
};

const SCORE_COLORS = ['#ff6b6b', '#f5c542', '#6b748a', '#5b8cff', '#43e8b0'];

// ── Custom Tooltip ──
const CustomTooltip = ({ active, payload, label }: any) => {
  if (!active || !payload?.length) return null;
  return (
    <div className="analytics-tooltip">
      <div className="label">{label}</div>
      {payload.map((p: any, i: number) => (
        <div key={i} className="value">
          {p.name}: <span>{p.value}</span>
        </div>
      ))}
    </div>
  );
};

const AdminAnalytics: React.FC<AdminAnalyticsProps> = () => {
  const [data, setData] = useState<AnalyticsData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [activePreset, setActivePreset] = useState('all');

  const fetchAnalytics = useCallback(async (preset: string) => {
    try {
      setLoading(true);
      setError(null);

      const filters: AnalyticsFilters = {};
      if (preset !== 'all') {
        const now = new Date();
        const days = preset === '7d' ? 7 : preset === '30d' ? 30 : 90;
        const from = new Date(now.getTime() - days * 24 * 60 * 60 * 1000);
        filters.from = from.toISOString();
        filters.to = now.toISOString();
      }

      const result = await adminService.getAnalytics(filters);
      setData(result);
    } catch (err: any) {
      setError(err.response?.data?.error || 'Failed to load analytics');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchAnalytics(activePreset);
  }, [activePreset, fetchAnalytics]);

  const handlePresetChange = (preset: string) => {
    setActivePreset(preset);
  };

  const getScoreClass = (score: number) => {
    if (score >= 80) return 'excellent';
    if (score >= 60) return 'good';
    if (score >= 40) return 'average';
    return 'poor';
  };

  const getRankClass = (rank: number) => {
    if (rank === 1) return 'gold';
    if (rank === 2) return 'silver';
    if (rank === 3) return 'bronze';
    return 'default';
  };

  const formatStatus = (status: string) =>
    status.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());

  // ── Radar data for score dimensions ──
  const radarData = data ? [
    { dimension: 'Code Quality', value: data.scoreDimensions.code_quality, max: 10 },
    { dimension: 'Functionality', value: data.scoreDimensions.functionality, max: 10 },
    { dimension: 'Documentation', value: data.scoreDimensions.documentation, max: 10 },
    { dimension: 'Timeliness', value: data.scoreDimensions.timeliness, max: 10 },
  ] : [];

  if (loading) {
    return (
      <div className="fade-in">
        <div className="page-header">
          <div>
            <h1 className="page-title">Analytics <span className="wf-note">Admin View</span></h1>
            <p className="page-subtitle">Program-wide performance insights</p>
          </div>
        </div>
        <div className="loader-wrapper">
          <div className="loading-wave">
            <div className="loading-bar"></div>
            <div className="loading-bar"></div>
            <div className="loading-bar"></div>
            <div className="loading-bar"></div>
          </div>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="fade-in">
        <div className="page-header">
          <div>
            <h1 className="page-title">Analytics</h1>
          </div>
        </div>
        <div className="error-banner">
          {error}
          <button className="btn btn-secondary btn-sm" style={{ marginLeft: 12 }} onClick={() => fetchAnalytics(activePreset)}>
            Retry
          </button>
        </div>
      </div>
    );
  }

  if (!data) return null;

  return (
    <div className="fade-in">
      {/* ── Header + Filters ── */}
      <div className="page-header">
        <div>
          <h1 className="page-title">Analytics <span className="wf-note">Admin View</span></h1>
          <p className="page-subtitle">Program-wide performance insights</p>
        </div>
        <div className="analytics-filter-bar">
          {DATE_PRESETS.map(p => (
            <button
              key={p.value}
              className={`date-filter-chip ${activePreset === p.value ? 'active' : ''}`}
              onClick={() => handlePresetChange(p.value)}
            >
              {p.label}
            </button>
          ))}
        </div>
      </div>

      {/* ── KPI Cards ── */}
      <div className="kpi-grid">
        <div className="kpi-card">
          <div className="kpi-label">Task Completion</div>
          <div className="kpi-value">{data.kpis.taskCompletionRate}%</div>
          <div className="kpi-sub">of all assigned tasks completed</div>
        </div>
        <div className="kpi-card">
          <div className="kpi-label">Avg. Eval Score</div>
          <div className="kpi-value">{data.kpis.avgEvaluationScore}<span style={{ fontSize: 14, color: 'var(--muted)' }}>/100</span></div>
          <div className="kpi-sub">{data.kpis.totalEvaluations} evaluations total</div>
        </div>
        <div className="kpi-card">
          <div className="kpi-label">Submission Rate</div>
          <div className="kpi-value">{data.kpis.submissionRate}%</div>
          <div className="kpi-sub">tasks with at least one submission</div>
        </div>
        <div className="kpi-card">
          <div className="kpi-label">Active Interns</div>
          <div className="kpi-value">{data.kpis.activeInternCount}<span style={{ fontSize: 14, color: 'var(--muted)' }}>/{data.kpis.totalInternCount}</span></div>
          <div className="kpi-sub">currently active in program</div>
        </div>
      </div>

      {/* ── Charts Row ── */}
      <div className="analytics-grid">
        {/* Task Status Breakdown */}
        <div className="chart-card">
          <div className="chart-card-header">
            <div className="chart-card-title">Task Status Breakdown</div>
          </div>
          <div className="chart-card-body">
            {data.taskStatusBreakdown.length === 0 ? (
              <div className="chart-empty">No task data available</div>
            ) : (
              <ResponsiveContainer width="100%" height={280}>
                <BarChart data={data.taskStatusBreakdown} layout="vertical" margin={{ left: 20, right: 20 }}>
                  <CartesianGrid strokeDasharray="3 3" horizontal={false} />
                  <XAxis type="number" />
                  <YAxis dataKey="status" type="category" width={90} tickFormatter={formatStatus} />
                  <Tooltip content={<CustomTooltip />} />
                  <Bar dataKey="count" name="Tasks" radius={[0, 4, 4, 0]} barSize={22}>
                    {data.taskStatusBreakdown.map((entry, i) => (
                      <Cell key={i} fill={STATUS_COLORS[entry.status] || '#5b8cff'} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            )}
          </div>
        </div>

        {/* Score Distribution */}
        <div className="chart-card">
          <div className="chart-card-header">
            <div className="chart-card-title">Score Distribution</div>
          </div>
          <div className="chart-card-body">
            {data.scoreDistribution.every(d => d.count === 0) ? (
              <div className="chart-empty">No evaluation data available</div>
            ) : (
              <ResponsiveContainer width="100%" height={280}>
                <BarChart data={data.scoreDistribution} margin={{ top: 10, right: 20, bottom: 5 }}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} />
                  <XAxis dataKey="range" />
                  <YAxis allowDecimals={false} />
                  <Tooltip content={<CustomTooltip />} />
                  <Bar dataKey="count" name="Evaluations" radius={[4, 4, 0, 0]} barSize={40}>
                    {data.scoreDistribution.map((_, i) => (
                      <Cell key={i} fill={SCORE_COLORS[i]} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            )}
          </div>
        </div>
      </div>

      {/* ── Dimensions Row ── */}
      <div className="analytics-grid">
        {/* Radar Chart */}
        <div className="chart-card">
          <div className="chart-card-header">
            <div className="chart-card-title">Evaluation Dimensions</div>
            <span className="wf-note">avg out of 10</span>
          </div>
          <div className="chart-card-body">
            {radarData.every(d => d.value === 0) ? (
              <div className="chart-empty">No evaluation data available</div>
            ) : (
              <ResponsiveContainer width="100%" height={280}>
                <RadarChart data={radarData} cx="50%" cy="50%" outerRadius="70%">
                  <PolarGrid stroke="var(--border)" />
                  <PolarAngleAxis dataKey="dimension" tick={{ fill: 'var(--muted)', fontSize: 11 }} />
                  <PolarRadiusAxis domain={[0, 10]} tick={{ fill: 'var(--muted)', fontSize: 10 }} />
                  <Radar
                    name="Score"
                    dataKey="value"
                    stroke="#5b8cff"
                    fill="rgba(91, 140, 255, 0.2)"
                    strokeWidth={2}
                    dot={{ fill: '#5b8cff', r: 4 }}
                  />
                  <Tooltip content={<CustomTooltip />} />
                </RadarChart>
              </ResponsiveContainer>
            )}
          </div>
        </div>

        {/* Dimension Breakdown */}
        <div className="chart-card">
          <div className="chart-card-header">
            <div className="chart-card-title">Dimension Breakdown</div>
          </div>
          <div className="chart-card-body">
            <div className="dimension-grid">
              {[
                { key: 'code_quality', label: 'Code Quality', color: '#5b8cff' },
                { key: 'functionality', label: 'Functionality', color: '#43e8b0' },
                { key: 'documentation', label: 'Documentation', color: '#f5c542' },
                { key: 'timeliness', label: 'Timeliness', color: '#ff6b6b' },
              ].map(dim => {
                const val = data.scoreDimensions[dim.key as keyof typeof data.scoreDimensions];
                return (
                  <div className="dimension-item" key={dim.key}>
                    <div className="dimension-label">{dim.label}</div>
                    <div className="dimension-value">
                      {val}<span className="dimension-max">/10</span>
                    </div>
                    <div className="dimension-bar-track">
                      <div
                        className="dimension-bar-fill"
                        style={{ width: `${(val / 10) * 100}%`, background: dim.color }}
                      />
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      </div>

      {/* ── Cohort Performance ── */}
      <div className="chart-card analytics-full">
        <div className="chart-card-header">
          <div className="chart-card-title">Cohort Performance</div>
          <span className="wf-note">{data.cohortPerformance.length} cohorts</span>
        </div>
        <div className="chart-card-body" style={{ padding: 0 }}>
          {data.cohortPerformance.length === 0 ? (
            <div className="chart-empty">No cohort data available</div>
          ) : (
            <div className="table-wrapper">
              <table className="cohort-perf-table">
                <thead>
                  <tr>
                    <th>Cohort</th>
                    <th>Status</th>
                    <th>Interns</th>
                    <th>Avg Score</th>
                    <th>Task Progress</th>
                  </tr>
                </thead>
                <tbody>
                  {data.cohortPerformance.map(c => (
                    <tr key={c.id}>
                      <td><strong>{c.name}</strong></td>
                      <td>
                        <span className={`cohort-status-badge ${c.status}`}>
                          {c.status}
                        </span>
                      </td>
                      <td>{c.internCount}</td>
                      <td>
                        <span className={`score-pill ${getScoreClass(c.avgScore)}`}>
                          {c.avgScore || '—'}
                        </span>
                      </td>
                      <td>
                        <div className="mini-progress">
                          <div className="mini-progress-bar">
                            <div className="mini-progress-fill" style={{ width: `${c.taskProgress}%` }} />
                          </div>
                          <span className="mini-progress-label">{c.taskProgress}%</span>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>

      {/* ── Leaderboard ── */}
      <div className="chart-card analytics-full">
        <div className="chart-card-header">
          <div className="chart-card-title">🏆 Top Performing Interns</div>
          <span className="wf-note">by avg score</span>
        </div>
        <div className="chart-card-body" style={{ padding: 0 }}>
          {data.topInterns.length === 0 ? (
            <div className="chart-empty">No evaluated interns yet</div>
          ) : (
            <div className="table-wrapper">
              <table className="leaderboard-table">
                <thead>
                  <tr>
                    <th>Rank</th>
                    <th>Intern</th>
                    <th>Cohort</th>
                    <th>Avg Score</th>
                    <th>Tasks Done</th>
                    <th>Submissions</th>
                  </tr>
                </thead>
                <tbody>
                  {data.topInterns.map(intern => (
                    <tr key={intern.id}>
                      <td>
                        <span className={`rank-badge ${getRankClass(intern.rank)}`}>
                          {intern.rank}
                        </span>
                      </td>
                      <td>
                        <div className="intern-cell">
                          <div className={`avatar micro ${getRankClass(intern.rank) === 'gold' ? 'yellow' : getRankClass(intern.rank) === 'silver' ? 'blue' : 'green'}`}>
                            {intern.name.split(' ').map(w => w[0]).slice(0, 2).join('').toUpperCase()}
                          </div>
                          <strong>{intern.name}</strong>
                        </div>
                      </td>
                      <td><span className="intern-cohort">{intern.cohort}</span></td>
                      <td>
                        <span className={`score-pill ${getScoreClass(intern.avgScore)}`}>
                          {intern.avgScore}
                        </span>
                      </td>
                      <td>{intern.tasksCompleted}</td>
                      <td>{intern.submissions}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default AdminAnalytics;

import React, { useState, useEffect, useCallback } from 'react';
import Badge from '@/components/Shared/Badge';
import Pagination from '@/components/Shared/Pagination';
import ConfirmDialog from '@/components/Shared/ConfirmDialog';
import CohortFormModal from './CohortFormModal';
import CohortMembersModal from './CohortMembersModal';
import { cohortService } from '@/services/cohortService';
import type { Cohort, PaginatedResponse } from '@/types';

interface AdminCohortsProps {
    onNavigate: (screen: string) => void;
}

const AdminCohorts: React.FC<AdminCohortsProps> = () => {
    const [data, setData] = useState<PaginatedResponse<Cohort> | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [page, setPage] = useState(1);
    const [formOpen, setFormOpen] = useState(false);
    const [editCohort, setEditCohort] = useState<Cohort | null>(null);
    const [deleteTarget, setDeleteTarget] = useState<Cohort | null>(null);
    const [membersTarget, setMembersTarget] = useState<Cohort | null>(null);

    const fetchCohorts = useCallback(async () => {
        setLoading(true); setError('');
        try {
            const result = await cohortService.getCohorts({ page, page_size: 10, sort: '-created_at' });
            setData(result);
        } catch (err: any) {
            setError(err.response?.data?.error?.message || 'Failed to load cohorts');
        } finally { setLoading(false); }
    }, [page]);

    useEffect(() => { fetchCohorts(); }, [fetchCohorts]);

    const handleCreate = async (formData: any) => {
        try { await cohortService.createCohort(formData); setFormOpen(false); fetchCohorts(); }
        catch (err: any) { alert(err.response?.data?.error?.message || 'Failed to create cohort'); }
    };

    const handleEdit = async (formData: any) => {
        if (!editCohort) return;
        try { await cohortService.updateCohort(editCohort.id, formData); setEditCohort(null); setFormOpen(false); fetchCohorts(); }
        catch (err: any) { alert(err.response?.data?.error?.message || 'Failed to update cohort'); }
    };

    const handleDelete = async () => {
        if (!deleteTarget) return;
        try { await cohortService.deleteCohort(deleteTarget.id); setDeleteTarget(null); fetchCohorts(); }
        catch (err: any) { alert(err.response?.data?.error?.message || 'Failed to delete cohort'); }
    };

    const formatDate = (d: string | null) => d ? new Date(d).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' }) : '—';

    return (
        <div className="screen-admin-cohorts fade-in">
            <div className="page-header">
                <div>
                    <div className="page-title">Cohort Management <span className="wf-note">Admin View</span></div>
                    <div className="page-subtitle">Training batches and enrollment</div>
                </div>
                <button className="btn btn-primary btn-sm" onClick={() => { setEditCohort(null); setFormOpen(true); }}>+ New Cohort</button>
            </div>

            {error && <div className="error-banner">{error}</div>}

            {loading ? (
                      <div className="loader-wrapper">
        <div className="loading-wave">
          <div className="loading-bar"></div>
          <div className="loading-bar"></div>
          <div className="loading-bar"></div>
          <div className="loading-bar"></div>
        </div>
      </div>
            ) : (
                <div className="admin-card">
                    <div className="table-wrapper">
                        <table className="admin-table">
                            <thead>
                                <tr>
                                    <th>Name</th>
                                    <th>Description</th>
                                    <th>Start</th>
                                    <th>End</th>
                                    <th>Actions</th>
                                </tr>
                            </thead>
                            <tbody>
                                {data?.items.map(cohort => (
                                    <tr key={cohort.id}>
                                        <td><strong>{cohort.name}</strong></td>
                                        <td className="time-muted">{cohort.description || '—'}</td>
                                        <td className="time-muted">{formatDate(cohort.start_date)}</td>
                                        <td className="time-muted">{formatDate(cohort.end_date)}</td>
                                        <td>
                                            <div className="btn-group">
                                                <button className="btn btn-secondary btn-sm" onClick={() => { setEditCohort(cohort); setFormOpen(true); }}>Edit</button>
                                                <button className="btn btn-secondary btn-sm" style={{ color: '#5ba4f5' }} onClick={() => setMembersTarget(cohort)}>Manage Interns</button>
                                                <button className="btn btn-secondary btn-sm" style={{ color: 'var(--accent2)' }} onClick={() => setDeleteTarget(cohort)}>Delete</button>
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                                {data?.items.length === 0 && (
                                    <tr><td colSpan={5} style={{ textAlign: 'center', padding: '40px', color: 'var(--muted)' }}>No cohorts found</td></tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                    {data && <Pagination page={data.page} pages={data.pages} total={data.total} onPageChange={setPage} />}
                </div>
            )}

            <CohortFormModal isOpen={formOpen} editCohort={editCohort} onSubmit={editCohort ? handleEdit : handleCreate} onClose={() => { setFormOpen(false); setEditCohort(null); }} />
            <CohortMembersModal isOpen={!!membersTarget} cohort={membersTarget} onClose={() => setMembersTarget(null)} />
            <ConfirmDialog isOpen={!!deleteTarget} title="Delete Cohort" message={`Delete "${deleteTarget?.name}"? This cannot be undone.`} confirmLabel="Delete" variant="danger" onConfirm={handleDelete} onCancel={() => setDeleteTarget(null)} />
        </div>
    );
};

export default AdminCohorts;

import React, { useEffect, useState, useCallback } from 'react';
import { evaluationService, EvaluationQueryParams } from '@/services/evaluationService';
import type { Evaluation } from '@/types';
import Pagination from '@/components/Shared/Pagination';
import ConfirmDialog from '@/components/Shared/ConfirmDialog';
import EvaluationFormModal from './EvaluationFormModal';
import './AdminDashboard.css';

interface AdminEvaluationsProps {
  onNavigate?: (screen: string) => void;
}

const AdminEvaluations: React.FC<AdminEvaluationsProps> = () => {
  const [evaluations, setEvaluations] = useState<Evaluation[]>([]);
  const [pagination, setPagination] = useState({ page: 1, pages: 1, total: 0 });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingEval, setEditingEval] = useState<Evaluation | null>(null);
  const [deleteConfirmId, setDeleteConfirmId] = useState<number | null>(null);

  const fetchEvaluations = useCallback(async (page = 1) => {
    try {
      setLoading(true);
      setError(null);
      const params: EvaluationQueryParams = { page, page_size: 15 };
      const res = await evaluationService.getEvaluations(params);
      setEvaluations(res.items);
      setPagination({ page: res.page, pages: res.pages, total: res.total });
    } catch (err: any) {
      const errorData = err.response?.data?.error;
      const errorMessage = typeof errorData === 'object' && errorData !== null ? errorData.message : errorData || 'Failed to load evaluations';
      setError(errorMessage);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    const delay = setTimeout(() => fetchEvaluations(1), 300);
    return () => clearTimeout(delay);
  }, [fetchEvaluations]);

  const handleCreate = () => {
    setEditingEval(null);
    setIsFormOpen(true);
  };

  const handleEdit = (evaluation: Evaluation) => {
    setEditingEval(evaluation);
    setIsFormOpen(true);
  };

  const handleDelete = async () => {
    if (!deleteConfirmId) return;
    try {
      await evaluationService.deleteEvaluation(deleteConfirmId);
      setDeleteConfirmId(null);
      fetchEvaluations(pagination.page);
    } catch (err: any) {
      const errorData = err.response?.data?.error;
      const errorMessage = typeof errorData === 'object' && errorData !== null ? errorData.message : errorData || 'Failed to delete evaluation';
      setError(errorMessage);
      setDeleteConfirmId(null);
    }
  };

  const onFormSubmit = async (data: any) => {
    try {
      if (editingEval) {
        await evaluationService.updateEvaluation(editingEval.id, data);
      } else {
        await evaluationService.createEvaluation(data);
      }
      setIsFormOpen(false);
      fetchEvaluations(pagination.page);
    } catch (err: any) {
      console.error(err);
      throw err;
    }
  };

  const getScoreColor = (score: number) => {
    if (score >= 90) return 'var(--success)';
    if (score >= 70) return 'var(--accent)';
    if (score >= 50) return 'var(--accent2)';
    return 'var(--danger)';
  };

  return (
    <div className="view-container">
      <div className="page-header">
        <div>
          <h1 className="page-title">Evaluations Dashboard</h1>
          <p className="page-subtitle">Track and analyze intern performance scores</p>
        </div>
        <button className="btn btn-primary" onClick={handleCreate}>+ Evaluate Submission</button>
      </div>

      {error && <div className="error-banner">{error}</div>}

      <div className="admin-card">
        {loading ? (
          <div className="loader-wrapper">
            <div className="loading-wave">
              <div className="loading-bar"></div>
              <div className="loading-bar"></div>
              <div className="loading-bar"></div>
              <div className="loading-bar"></div>
            </div>
          </div>
        ) : evaluations.length === 0 ? (
          <div className="empty-state">No evaluations found</div>
        ) : (
          <div className="table-wrapper">
            <table className="admin-table">
              <thead>
                <tr>
                  <th>Submission ID</th>
                  <th>Scores</th>
                  <th>Overall</th>
                  <th>Feedback Summary</th>
                  <th style={{ textAlign: 'right' }}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {evaluations.map(ev => (
                  <tr key={ev.id}>
                    <td>
                      <strong>Sub #{ev.submission_id}</strong>
                      <div className="time-muted">Eval by Trainer #{ev.trainer_id}</div>
                    </td>
                    <td>
                      <div style={{ fontSize: '0.8rem', lineHeight: '1.4' }}>
                        <div>Code: {ev.code_quality}%</div>
                        <div>Func: {ev.functionality}%</div>
                        <div>Docs: {ev.documentation}%</div>
                      </div>
                    </td>
                    <td>
                      <div style={{ fontWeight: 600, fontSize: '1.2rem', color: getScoreColor(ev.score || 0) }}>
                        {ev.score || 0}%
                      </div>
                    </td>
                    <td style={{ maxWidth: '250px' }}>
                      <div style={{ whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', fontSize: '0.9rem' }}>
                        {ev.feedback || 'No feedback provided'}
                      </div>
                    </td>
                    <td style={{ textAlign: 'right' }}>
                      <button className="btn btn-secondary btn-sm" onClick={() => handleEdit(ev)} style={{ marginRight: '8px' }}>Edit</button>
                      <button className="btn btn-secondary btn-sm" onClick={() => setDeleteConfirmId(ev.id)} style={{ color: 'var(--accent2)', borderColor: 'rgba(255,107,107,0.3)' }}>Delete</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {pagination.pages > 1 && (
        <Pagination 
          page={pagination.page} 
          pages={pagination.pages} 
          total={pagination.total}
          onPageChange={fetchEvaluations} 
        />
      )}

      <EvaluationFormModal 
        isOpen={isFormOpen} 
        editEvaluation={editingEval} 
        onSubmit={onFormSubmit} 
        onClose={() => setIsFormOpen(false)} 
      />

      <ConfirmDialog 
        isOpen={!!deleteConfirmId}
        title="Delete Evaluation"
        message="Are you sure you want to delete this evaluation? This action cannot be undone."
        onConfirm={handleDelete}
        onCancel={() => setDeleteConfirmId(null)}
        confirmLabel="Delete"
        variant="danger"
      />
    </div>
  );
};

export default AdminEvaluations;

import React, { useState, useEffect, useCallback } from 'react';
import Pagination from '@/components/Shared/Pagination';
import ConfirmDialog from '@/components/Shared/ConfirmDialog';
import ProjectFormModal from './ProjectFormModal';
import { projectService } from '@/services/projectService';
import type { Project, PaginatedResponse } from '@/types';

interface AdminProjectsProps {
    onNavigate: (screen: string) => void;
}

const AdminProjects: React.FC<AdminProjectsProps> = () => {
    const [data, setData] = useState<PaginatedResponse<Project> | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [page, setPage] = useState(1);
    const [formOpen, setFormOpen] = useState(false);
    const [editProject, setEditProject] = useState<Project | null>(null);
    const [deleteTarget, setDeleteTarget] = useState<Project | null>(null);

    const fetchProjects = useCallback(async () => {
        setLoading(true); setError('');
        try {
            const result = await projectService.getProjects({ page, page_size: 10, sort: '-created_at' });
            setData(result);
        } catch (err: any) {
            setError(err.response?.data?.error?.message || 'Failed to load projects');
        } finally { setLoading(false); }
    }, [page]);

    useEffect(() => { fetchProjects(); }, [fetchProjects]);

    const handleCreate = async (formData: any) => {
        try { await projectService.createProject(formData); setFormOpen(false); fetchProjects(); }
        catch (err: any) { alert(err.response?.data?.error?.message || 'Failed to create project'); }
    };

    const handleEdit = async (formData: any) => {
        if (!editProject) return;
        try { await projectService.updateProject(editProject.id, formData); setEditProject(null); setFormOpen(false); fetchProjects(); }
        catch (err: any) { alert(err.response?.data?.error?.message || 'Failed to update project'); }
    };

    const handleDelete = async () => {
        if (!deleteTarget) return;
        try { await projectService.deleteProject(deleteTarget.id); setDeleteTarget(null); fetchProjects(); }
        catch (err: any) { alert(err.response?.data?.error?.message || 'Failed to delete project'); }
    };

    return (
        <div className="screen-admin-projects fade-in">
            <div className="page-header">
                <div>
                    <div className="page-title">Project Management <span className="wf-note">Admin View</span></div>
                    <div className="page-subtitle">All active and past projects</div>
                </div>
                <button className="btn btn-primary btn-sm" onClick={() => { setEditProject(null); setFormOpen(true); }}>+ New Project</button>
            </div>

            {error && <div className="error-banner">{error}</div>}

            {loading ? (
                      <div className="loader-wrapper">
        <div className="loading-wave">
          <div className="loading-bar"></div>
          <div className="loading-bar"></div>
          <div className="loading-bar"></div>
          <div className="loading-bar"></div>
        </div>
      </div>
            ) : (
                <div className="admin-card">
                    <div className="table-wrapper">
                        <table className="admin-table">
                            <thead>
                                <tr>
                                    <th>Title</th>
                                    <th>Description</th>
                                    <th>Cohort ID</th>
                                    <th>Created</th>
                                    <th>Actions</th>
                                </tr>
                            </thead>
                            <tbody>
                                {data?.items.map(project => (
                                    <tr key={project.id}>
                                        <td><strong>{project.title}</strong></td>
                                        <td className="time-muted">{project.description || '—'}</td>
                                        <td className="time-muted">{project.cohort_id}</td>
                                        <td className="time-muted">{new Date(project.created_at).toLocaleDateString('en-IN', { day: 'numeric', month: 'short' })}</td>
                                        <td>
                                            <div className="btn-group">
                                                <button className="btn btn-secondary btn-sm" onClick={() => { setEditProject(project); setFormOpen(true); }}>Edit</button>
                                                <button className="btn btn-secondary btn-sm" style={{ color: 'var(--accent2)' }} onClick={() => setDeleteTarget(project)}>Delete</button>
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                                {data?.items.length === 0 && (
                                    <tr><td colSpan={5} style={{ textAlign: 'center', padding: '40px', color: 'var(--muted)' }}>No projects found</td></tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                    {data && <Pagination page={data.page} pages={data.pages} total={data.total} onPageChange={setPage} />}
                </div>
            )}

            <ProjectFormModal isOpen={formOpen} editProject={editProject} onSubmit={editProject ? handleEdit : handleCreate} onClose={() => { setFormOpen(false); setEditProject(null); }} />
            <ConfirmDialog isOpen={!!deleteTarget} title="Delete Project" message={`Delete "${deleteTarget?.title}"? This cannot be undone.`} confirmLabel="Delete" variant="danger" onConfirm={handleDelete} onCancel={() => setDeleteTarget(null)} />
        </div>
    );
};

export default AdminProjects;

// AdminSubmissions.tsx
import React, { useEffect, useState, useCallback } from 'react';
import { submissionService, SubmissionQueryParams } from '@/services/submissionService';
import type { Submission } from '@/types';
import Pagination from '@/components/Shared/Pagination';
import Badge from '@/components/Shared/Badge';
import './AdminDashboard.css';

interface AdminSubmissionsProps {
  onNavigate?: (screen: string) => void;
}

const AdminSubmissions: React.FC<AdminSubmissionsProps> = () => {
  const [submissions, setSubmissions] = useState<Submission[]>([]);
  const [pagination, setPagination] = useState({ page: 1, pages: 1, total: 0 });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Filters
  const [statusFilter, setStatusFilter] = useState('');

  // Updates
  const [updatingId, setUpdatingId] = useState<number | null>(null);

  const fetchSubmissions = useCallback(async (page = 1) => {
    try {
      setLoading(true);
      setError(null);
      const params: SubmissionQueryParams = { page, page_size: 15 };
      if (statusFilter) params.status = statusFilter;
      
      const res = await submissionService.getSubmissions(params);
      setSubmissions(res.items);
      setPagination({ page: res.page, pages: res.pages, total: res.total });
    } catch (err: any) {
      setError(err.response?.data?.error || 'Failed to load submissions');
    } finally {
      setLoading(false);
    }
  }, [statusFilter]);

  useEffect(() => {
    const delay = setTimeout(() => fetchSubmissions(1), 300);
    return () => clearTimeout(delay);
  }, [fetchSubmissions]);

  const handleStatusUpdate = async (id: number, status: 'reviewed' | 'revision_requested') => {
    try {
      setUpdatingId(id);
      await submissionService.updateSubmissionStatus(id, status);
      fetchSubmissions(pagination.page);
    } catch (err: any) {
      setError(err.response?.data?.error || 'Failed to update status');
    } finally {
      setUpdatingId(null);
    }
  };

  const getStatusColor = (s: string) => {
    switch (s) {
      case 'submitted': return 'gray';
      case 'reviewed': return 'green';
      case 'revision_requested': return 'yellow'; // orange/yellow
      default: return 'gray';
    }
  };

  return (
    <div className="view-container">
      <div className="page-header">
        <div>
          <h1 className="page-title">Submissions Review</h1>
          <p className="page-subtitle">Track and review intern project submissions</p>
        </div>
      </div>

      {error && <div className="error-banner">{error}</div>}

      <div className="search-row">
        {/* Submissions don't have titles, they tie to tasks, so searching by title requires joining or distinct UI. Assuming we don't have text search for now. */}
        <div style={{ flex: 1 }}></div>
        <div className="filter-chips">
          <button className={`filter-chip ${statusFilter === '' ? 'active' : ''}`} onClick={() => setStatusFilter('')}>All</button>
          <button className={`filter-chip ${statusFilter === 'submitted' ? 'active' : ''}`} onClick={() => setStatusFilter('submitted')}>Submitted</button>
          <button className={`filter-chip ${statusFilter === 'reviewed' ? 'active' : ''}`} onClick={() => setStatusFilter('reviewed')}>Reviewed</button>
          <button className={`filter-chip ${statusFilter === 'revision_requested' ? 'active' : ''}`} onClick={() => setStatusFilter('revision_requested')}>Needs Revision</button>
        </div>
      </div>

      <div className="admin-card">
        {loading ? (
          <div className="loader-wrapper">
            <div className="loading-wave">
              <div className="loading-bar"></div>
              <div className="loading-bar"></div>
              <div className="loading-bar"></div>
              <div className="loading-bar"></div>
            </div>
          </div>
        ) : submissions.length === 0 ? (
          <div className="empty-state">No submissions found</div>
        ) : (
          <div className="table-wrapper">
            <table className="admin-table">
              <thead>
                <tr>
                  <th>Task</th>
                  <th>Intern</th>
                  <th>Submission Info</th>
                  <th>Status</th>
                  <th>Date</th>
                  <th style={{ textAlign: 'right' }}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {submissions.map(sub => (
                  <tr key={sub.id}>
                    <td><strong>{sub.task_title || `Task #${sub.task_id}`}</strong></td>
                    <td>
                      <div className="user-cell">
                        <div className="avatar micro">{sub.intern_name?.substring(0,2).toUpperCase() || 'I'}</div>
                        {sub.intern_name || `Intern #${sub.intern_id}`}
                      </div>
                    </td>
                    <td>
                      {sub.github_url && <a href={sub.github_url} target="_blank" rel="noreferrer" className="stat-value" style={{ fontSize: '0.85rem' }}>GitHub Link</a>}<br/>
                      {sub.demo_url && <a href={sub.demo_url} target="_blank" rel="noreferrer" className="stat-value" style={{ fontSize: '0.85rem' }}>Live Demo</a>}
                    </td>
                    <td><Badge variant={getStatusColor(sub.status)}>{sub.status.replace('_', ' ')}</Badge></td>
                    <td className="time-muted">{new Date(sub.submitted_at).toLocaleDateString()}</td>
                    <td style={{ textAlign: 'right' }}>
                      {sub.status === 'submitted' && (
                        <>
                          <button className="btn btn-primary btn-sm" onClick={() => handleStatusUpdate(sub.id, 'reviewed')} disabled={updatingId === sub.id} style={{ marginRight: '8px' }}>
                            Mark Reviewed
                          </button>
                          <button className="btn btn-secondary btn-sm" onClick={() => handleStatusUpdate(sub.id, 'revision_requested')} disabled={updatingId === sub.id}>
                            Request Revision
                          </button>
                        </>
                      )}
                      {sub.status !== 'submitted' && (
                        <span className="time-muted" style={{ fontSize: '0.85rem' }}>No pending actions</span>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {pagination.pages > 1 && (
        <Pagination 
          page={pagination.page} 
          pages={pagination.pages} 
          total={pagination.total}
          onPageChange={fetchSubmissions} 
        />
      )}
    </div>
  );
};

export default AdminSubmissions;

// AdminTasks.tsx
import React, { useEffect, useState, useCallback } from 'react';
import { taskService, TaskQueryParams } from '@/services/taskService';
import type { Task } from '@/types';
import Pagination from '@/components/Shared/Pagination';
import TaskFormModal from './TaskFormModal';
import ConfirmDialog from '@/components/Shared/ConfirmDialog';
import Badge from '@/components/Shared/Badge';
import { useAuth } from '@/context/AuthContext';
import './AdminDashboard.css'; // Reuse dashboard table styles

interface AdminTasksProps {
  onNavigate?: (screen: string) => void;
}

const AdminTasks: React.FC<AdminTasksProps> = () => {
  const { user } = useAuth();
  const [tasks, setTasks] = useState<Task[]>([]);
  const [pagination, setPagination] = useState({ page: 1, pages: 1, total: 0 });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Filters
  const [statusFilter, setStatusFilter] = useState('');
  const [priorityFilter, setPriorityFilter] = useState('');
  const [search, setSearch] = useState('');

  // Modals
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingTask, setEditingTask] = useState<Task | null>(null);
  const [deleteConfirmId, setDeleteConfirmId] = useState<number | null>(null);

  const fetchTasks = useCallback(async (page = 1) => {
    try {
      setLoading(true);
      setError(null);
      const params: TaskQueryParams = { page, page_size: 15 };
      if (statusFilter) params.status = statusFilter;
      if (priorityFilter) params.priority = priorityFilter;
      if (search) params.search = search;
      
      const res = await taskService.getTasks(params);
      setTasks(res.items);
      setPagination({ page: res.page, pages: res.pages, total: res.total });
    } catch (err: any) {
      setError(err.response?.data?.error || 'Failed to load tasks');
    } finally {
      setLoading(false);
    }
  }, [statusFilter, priorityFilter, search]);

  useEffect(() => {
    const delay = setTimeout(() => fetchTasks(1), 300);
    return () => clearTimeout(delay);
  }, [fetchTasks]);

  const handleCreate = () => {
    setEditingTask(null);
    setIsFormOpen(true);
  };

  const handleEdit = (task: Task) => {
    setEditingTask(task);
    setIsFormOpen(true);
  };

  const handleDelete = async () => {
    if (!deleteConfirmId) return;
    try {
      await taskService.deleteTask(deleteConfirmId);
      setDeleteConfirmId(null);
      fetchTasks(pagination.page);
    } catch (err: any) {
      setError(err.response?.data?.error || 'Failed to delete task');
      setDeleteConfirmId(null);
    }
  };

  const onFormSubmit = async (data: any) => {
    try {
      if (editingTask) {
        await taskService.updateTask(editingTask.id, data);
      } else {
        await taskService.createTask({ ...data, created_by: user?.id });
      }
      setIsFormOpen(false);
      fetchTasks(pagination.page);
    } catch (err: any) {
      console.error(err);
      throw err; // Let modal handle error display if we wanted to
    }
  };

  const getPriorityColor = (p: string) => {
    if (p === 'low') return 'green';
    if (p === 'medium') return 'blue';
    if (p === 'high') return 'yellow';
    return 'red'; // critical
  };

  const getStatusColor = (s: string) => {
    if (s === 'pending') return 'gray';
    if (s === 'in_progress') return 'blue';
    if (s === 'completed') return 'green';
    return 'red';
  };

  return (
    <div className="view-container">
      <div className="page-header">
        <div>
          <h1 className="page-title">Task Assignment</h1>
          <p className="page-subtitle">Manage and assign tasks to interns</p>
        </div>
        <button className="btn btn-primary" onClick={handleCreate}>+ New Task</button>
      </div>

      {error && <div className="error-banner">{error}</div>}

      <div className="search-row">
        <input 
          type="text" 
          className="search-input" 
          placeholder="Search tasks..." 
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
        <div className="filter-chips">
          <button className={`filter-chip ${statusFilter === '' ? 'active' : ''}`} onClick={() => setStatusFilter('')}>All Status</button>
          <button className={`filter-chip ${statusFilter === 'pending' ? 'active' : ''}`} onClick={() => setStatusFilter('pending')}>Pending</button>
          <button className={`filter-chip ${statusFilter === 'in_progress' ? 'active' : ''}`} onClick={() => setStatusFilter('in_progress')}>In Progress</button>
          <button className={`filter-chip ${statusFilter === 'completed' ? 'active' : ''}`} onClick={() => setStatusFilter('completed')}>Completed</button>
        </div>
        <div className="filter-chips">
          <button className={`filter-chip ${priorityFilter === '' ? 'active' : ''}`} onClick={() => setPriorityFilter('')}>All Priorities</button>
          <button className={`filter-chip ${priorityFilter === 'high' ? 'active' : ''}`} onClick={() => setPriorityFilter('high')}>High</button>
          <button className={`filter-chip ${priorityFilter === 'critical' ? 'active' : ''}`} onClick={() => setPriorityFilter('critical')}>Critical</button>
        </div>
      </div>

      <div className="admin-card">
        {loading ? (
          <div className="loader-wrapper">
            <div className="loading-wave">
              <div className="loading-bar"></div>
              <div className="loading-bar"></div>
              <div className="loading-bar"></div>
              <div className="loading-bar"></div>
            </div>
          </div>
        ) : tasks.length === 0 ? (
          <div className="empty-state">No tasks found</div>
        ) : (
          <div className="table-wrapper">
            <table className="admin-table">
              <thead>
                <tr>
                  <th>Title</th>
                  <th>Assigned To</th>
                  <th>Priority</th>
                  <th>Status</th>
                  <th>Due Date</th>
                  <th style={{ textAlign: 'right' }}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {tasks.map(task => (
                  <tr key={task.id}>
                    <td><strong>{task.title}</strong><div className="deadline-project">{task.project_title}</div></td>
                    <td>
                      <div className="user-cell">
                        <div className="avatar micro">{task.assigned_to_name?.substring(0,2).toUpperCase() || 'U'}</div>
                        {task.assigned_to_name || `User #${task.assigned_to}`}
                      </div>
                    </td>
                    <td><Badge variant={getPriorityColor(task.priority)}>{task.priority}</Badge></td>
                    <td><Badge variant={getStatusColor(task.status)}>{task.status.replace('_', ' ')}</Badge></td>
                    <td className="time-muted">{task.due_date ? new Date(task.due_date).toLocaleDateString() : 'No date'}</td>
                    <td style={{ textAlign: 'right' }}>
                      <button className="btn btn-secondary btn-sm" onClick={() => handleEdit(task)} style={{ marginRight: '8px' }}>Edit</button>
                      <button className="btn btn-secondary btn-sm" onClick={() => setDeleteConfirmId(task.id)} style={{ color: 'var(--accent2)', borderColor: 'rgba(255,107,107,0.3)' }}>Delete</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {pagination.pages > 1 && (
        <Pagination 
          page={pagination.page} 
          pages={pagination.pages} 
          total={pagination.total}
          onPageChange={fetchTasks} 
        />
      )}

      <TaskFormModal 
        isOpen={isFormOpen} 
        editTask={editingTask} 
        onSubmit={onFormSubmit} 
        onClose={() => setIsFormOpen(false)} 
      />

      <ConfirmDialog 
        isOpen={!!deleteConfirmId}
        title="Delete Task"
        message="Are you sure you want to delete this task? This action cannot be undone."
        onConfirm={handleDelete}
        onCancel={() => setDeleteConfirmId(null)}
        confirmLabel="Delete"
        variant="danger"
      />
    </div>
  );
};

export default AdminTasks;

import React, { useState, useEffect, useCallback } from 'react';
import Badge from '@/components/Shared/Badge';
import Pagination from '@/components/Shared/Pagination';
import ConfirmDialog from '@/components/Shared/ConfirmDialog';
import UserFormModal from './UserFormModal';
import TrainerAssignModal from './TrainerAssignModal';
import { userService } from '@/services/userService';
import type { User, PaginatedResponse } from '@/types';

interface AdminUsersProps {
    onNavigate: (screen: string) => void;
}

const AdminUsers: React.FC<AdminUsersProps> = () => {
    const [data, setData] = useState<PaginatedResponse<User> | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [search, setSearch] = useState('');
    const [roleFilter, setRoleFilter] = useState('');
    const [page, setPage] = useState(1);

    // Modal state
    const [formOpen, setFormOpen] = useState(false);
    const [editUser, setEditUser] = useState<User | null>(null);
    const [deleteTarget, setDeleteTarget] = useState<User | null>(null);
    const [assignTarget, setAssignTarget] = useState<User | null>(null);

    const fetchUsers = useCallback(async () => {
        setLoading(true);
        setError('');
        try {
            const result = await userService.getUsers({
                page, page_size: 10, sort: '-created_at',
                ...(roleFilter && { role: roleFilter }),
                ...(search && { search }),
            });
            setData(result);
        } catch (err: any) {
            setError(err.response?.data?.error?.message || 'Failed to load users');
        } finally {
            setLoading(false);
        }
    }, [page, roleFilter, search]);

    useEffect(() => { fetchUsers(); }, [fetchUsers]);

    // Debounced search
    const [searchInput, setSearchInput] = useState('');
    useEffect(() => {
        const t = setTimeout(() => { setSearch(searchInput); setPage(1); }, 400);
        return () => clearTimeout(t);
    }, [searchInput]);

    const handleCreate = async (formData: any) => {
        try {
            await userService.createUser(formData);
            setFormOpen(false);
            fetchUsers();
        } catch (err: any) {
            alert(err.response?.data?.error?.message || 'Failed to create user');
        }
    };

    const handleEdit = async (formData: any) => {
        if (!editUser) return;
        try {
            await userService.updateUser(editUser.id, formData);
            setEditUser(null);
            fetchUsers();
        } catch (err: any) {
            alert(err.response?.data?.error?.message || 'Failed to update user');
        }
    };

    const handleDelete = async () => {
        if (!deleteTarget) return;
        try {
            await userService.deleteUser(deleteTarget.id);
            setDeleteTarget(null);
            fetchUsers();
        } catch (err: any) {
            alert(err.response?.data?.error?.message || 'Failed to delete user');
        }
    };

    const roleBadgeColor = (role: string) => {
        switch (role) {
            case 'admin': return 'red';
            case 'trainer': return 'blue';
            case 'intern': return 'yellow';
            default: return 'gray';
        }
    };

    return (
        <div className="screen-admin-users fade-in">
            <div className="page-header">
                <div>
                    <div className="page-title">User Management <span className="wf-note">Admin View</span></div>
                    <div className="page-subtitle">Manage all system users</div>
                </div>
