import React, { useState, useEffect } from 'react';
import '@/components/Shared/ConfirmDialog.css';

interface CohortFormModalProps {
  isOpen: boolean;
  editCohort?: { id: number; name: string; description?: string | null; start_date?: string | null; end_date?: string | null } | null;
  onSubmit: (data: { name: string; description?: string; start_date?: string; end_date?: string }) => void;
  onClose: () => void;
}

const CohortFormModal: React.FC<CohortFormModalProps> = ({ isOpen, editCohort, onSubmit, onClose }) => {
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [errors, setErrors] = useState<Record<string, string>>({});

  useEffect(() => {
    if (editCohort) {
      setName(editCohort.name);
      setDescription(editCohort.description || '');
      setStartDate(editCohort.start_date?.split('T')[0] || '');
      setEndDate(editCohort.end_date?.split('T')[0] || '');
    } else {
      setName(''); setDescription(''); setStartDate(''); setEndDate('');
    }
    setErrors({});
  }, [editCohort, isOpen]);

  const validate = () => {
    const e: Record<string, string> = {};
    if (!name.trim()) e.name = 'Name is required';
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const handleSubmit = (evt: React.FormEvent) => {
    evt.preventDefault();
    if (!validate()) return;
    onSubmit({ name, description: description || undefined, start_date: startDate || undefined, end_date: endDate || undefined });
  };

  if (!isOpen) return null;

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-card" onClick={e => e.stopPropagation()}>
        <div className="modal-header">
          <h3 className="modal-title">{editCohort ? 'Edit Cohort' : 'New Cohort'}</h3>
        </div>
        <form onSubmit={handleSubmit}>
          <div className="modal-body">
            <div className="form-group">
              <label className="form-label">Cohort Name</label>
              <input className={`form-input ${errors.name ? 'error' : ''}`} value={name} onChange={e => setName(e.target.value)} placeholder="e.g. Cohort D" />
              {errors.name && <div className="form-error">{errors.name}</div>}
            </div>
            <div className="form-group">
              <label className="form-label">Description</label>
              <input className="form-input" value={description} onChange={e => setDescription(e.target.value)} placeholder="Track / focus area" />
            </div>
            <div className="form-group">
              <label className="form-label">Start Date</label>
              <input className="form-input" type="date" value={startDate} onChange={e => setStartDate(e.target.value)} />
            </div>
            <div className="form-group">
              <label className="form-label">End Date</label>
              <input className="form-input" type="date" value={endDate} onChange={e => setEndDate(e.target.value)} />
            </div>
          </div>
          <div className="modal-footer">
            <button type="button" className="btn btn-secondary btn-sm" onClick={onClose}>Cancel</button>
            <button type="submit" className="btn btn-primary btn-sm">{editCohort ? 'Save' : 'Create'}</button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default CohortFormModal;

import React, { useState, useEffect } from 'react';
import '@/components/Shared/ConfirmDialog.css';

interface Intern {
  id: number;
  name: string;
  email: string;
  is_active?: boolean;
}

interface CohortMembersModalProps {
  isOpen: boolean;
  cohort: { id: number; name: string } | null;
  onClose: () => void;
}

const CohortMembersModal: React.FC<CohortMembersModalProps> = ({ isOpen, cohort, onClose }) => {
  const [members, setMembers] = useState<Intern[]>([]);
  const [unassigned, setUnassigned] = useState<Intern[]>([]);
  const [loading, setLoading] = useState(true);
  const [acting, setActing] = useState<number | null>(null);
  const [error, setError] = useState('');

  const token = localStorage.getItem('token');
  const headers = { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' };

  const fetchData = async () => {
    if (!cohort) return;
    setLoading(true);
    setError('');
    try {
      const [membersRes, unassignedRes] = await Promise.all([
        fetch(`http://localhost:5000/api/cohorts/${cohort.id}/members`, { headers }).then(r => r.json()),
        fetch('http://localhost:5000/api/cohorts/meta/unassigned-interns', { headers }).then(r => r.json()),
      ]);
      setMembers(membersRes);
      setUnassigned(unassignedRes);
    } catch {
      setError('Failed to load data');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (isOpen && cohort) fetchData();
  }, [isOpen, cohort]);

  const handleAdd = async (internId: number) => {
    if (!cohort) return;
    setActing(internId);
    setError('');
    try {
      const resp = await fetch(`http://localhost:5000/api/cohorts/${cohort.id}/members`, {
        method: 'POST',
        headers,
        body: JSON.stringify({ intern_id: internId }),
      });
      if (!resp.ok) throw new Error();
      // Move from unassigned to members
      const intern = unassigned.find(u => u.id === internId);
      if (intern) {
        setMembers(prev => [...prev, intern].sort((a, b) => a.name.localeCompare(b.name)));
        setUnassigned(prev => prev.filter(u => u.id !== internId));
      }
    } catch {
      setError('Failed to add intern');
    } finally {
      setActing(null);
    }
  };

  const handleRemove = async (internId: number) => {
    if (!cohort) return;
    setActing(internId);
    setError('');
    try {
      const resp = await fetch(`http://localhost:5000/api/cohorts/${cohort.id}/members/${internId}`, {
        method: 'DELETE',
        headers,
      });
      if (!resp.ok) throw new Error();
      // Move from members to unassigned
      const intern = members.find(m => m.id === internId);
      if (intern) {
        setUnassigned(prev => [...prev, { id: intern.id, name: intern.name, email: intern.email }].sort((a, b) => a.name.localeCompare(b.name)));
        setMembers(prev => prev.filter(m => m.id !== internId));
      }
    } catch {
      setError('Failed to remove intern');
    } finally {
      setActing(null);
    }
  };

  if (!isOpen || !cohort) return null;

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-card" style={{ maxWidth: '580px' }} onClick={e => e.stopPropagation()}>
        <div className="modal-header">
          <h3 className="modal-title">Manage Interns — {cohort.name}</h3>
        </div>
        <div className="modal-body" style={{ maxHeight: '60vh', overflowY: 'auto' }}>
          {error && (
            <div style={{
              padding: '8px 12px',
              background: 'rgba(255, 99, 99, 0.12)',
              borderRadius: '4px',
              color: 'var(--accent2)',
              fontSize: '12px',
              marginBottom: '12px',
            }}>{error}</div>
          )}

          {loading ? (
            <div className="loader-wrapper" style={{ padding: '24px 0' }}>
              <div className="loading-wave">
                <div className="loading-bar"></div>
                <div className="loading-bar"></div>
                <div className="loading-bar"></div>
                <div className="loading-bar"></div>
              </div>
            </div>
          ) : (
            <>
              {/* Current Members */}
              <div style={{ marginBottom: '20px' }}>
                <div className="form-label" style={{ marginBottom: '8px', fontSize: '12px' }}>
                  Current Interns ({members.length})
                </div>
                {members.length === 0 ? (
                  <div style={{ fontSize: '13px', color: 'var(--muted)', padding: '12px 0' }}>
                    No interns in this cohort yet.
                  </div>
                ) : (
                  <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
                    {members.map(m => (
                      <div key={m.id} style={{
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'space-between',
                        padding: '8px 12px',
                        background: 'var(--surface2)',
                        borderRadius: '6px',
                        border: '1px solid var(--border)',
                      }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                          <div style={{
                            width: '30px',
                            height: '30px',
                            borderRadius: '50%',
                            background: 'linear-gradient(135deg, #f5c542, #e67e22)',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            fontSize: '11px',
                            fontWeight: 700,
                            color: '#fff',
                          }}>
                            {m.name.split(' ').map(w => w[0]).slice(0, 2).join('').toUpperCase()}
                          </div>
                          <div>
                            <div style={{ fontSize: '13px', fontWeight: 600, color: 'var(--text)' }}>{m.name}</div>
                            <div style={{ fontSize: '11px', color: 'var(--muted)' }}>{m.email}</div>
                          </div>
                        </div>
                        <button
                          className="btn btn-secondary btn-sm"
                          style={{ color: 'var(--accent2)', fontSize: '11px' }}
                          onClick={() => handleRemove(m.id)}
                          disabled={acting === m.id}
                          type="button"
                        >
                          {acting === m.id ? '...' : 'Remove'}
                        </button>
                      </div>
                    ))}
                  </div>
                )}
              </div>

              {/* Unassigned Interns */}
              {unassigned.length > 0 && (
                <div>
                  <div className="form-label" style={{ marginBottom: '8px', fontSize: '12px' }}>
                    Unassigned Interns ({unassigned.length})
                  </div>
                  <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
                    {unassigned.map(u => (
                      <div key={u.id} style={{
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'space-between',
                        padding: '8px 12px',
                        background: 'var(--surface)',
                        borderRadius: '6px',
                        border: '1px dashed var(--border)',
                      }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                          <div style={{
                            width: '30px',
                            height: '30px',
                            borderRadius: '50%',
                            background: 'var(--surface2)',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            fontSize: '11px',
                            fontWeight: 600,
                            color: 'var(--muted)',
                          }}>
                            {u.name.split(' ').map(w => w[0]).slice(0, 2).join('').toUpperCase()}
                          </div>
                          <div>
                            <div style={{ fontSize: '13px', color: 'var(--text)' }}>{u.name}</div>
                            <div style={{ fontSize: '11px', color: 'var(--muted)' }}>{u.email}</div>
                          </div>
                        </div>
                        <button
                          className="btn btn-primary btn-sm"
                          style={{ fontSize: '11px' }}
                          onClick={() => handleAdd(u.id)}
                          disabled={acting === u.id}
                          type="button"
                        >
                          {acting === u.id ? '...' : '+ Add'}
                        </button>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {unassigned.length === 0 && members.length > 0 && (
                <div style={{ fontSize: '12px', color: 'var(--muted)', textAlign: 'center', padding: '8px 0' }}>
                  All interns have been assigned to a cohort.
                </div>
              )}
            </>
          )}
        </div>
        <div className="modal-footer">
          <button type="button" className="btn btn-secondary btn-sm" onClick={onClose}>Close</button>
        </div>
      </div>
    </div>
  );
};

export default CohortMembersModal;

import React, { useState, useEffect } from 'react';
import { submissionService } from '@/services/submissionService';
import { userService } from '@/services/userService';
import type { Evaluation, Submission, User } from '@/types';
import '@/components/Shared/ConfirmDialog.css';

interface EvaluationFormModalProps {
  isOpen: boolean;
  editEvaluation?: Evaluation | null;
  onSubmit: (data: any) => Promise<void>;
  onClose: () => void;
}

const EvaluationFormModal: React.FC<EvaluationFormModalProps> = ({ isOpen, editEvaluation, onSubmit, onClose }) => {
  const [submissionId, setSubmissionId] = useState('');
  const [trainerId, setTrainerId] = useState('');
  const [codeQuality, setCodeQuality] = useState(1);
  const [functionality, setFunctionality] = useState(1);
  const [documentation, setDocumentation] = useState(1);
  const [timeliness, setTimeliness] = useState(1);
  const [feedback, setFeedback] = useState('');
  const [strengths, setStrengths] = useState('');
  const [improvements, setImprovements] = useState('');
  
  const [submissions, setSubmissions] = useState<Submission[]>([]);
  const [trainers, setTrainers] = useState<User[]>([]);
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    if (isOpen) {
      submissionService.getSubmissions({ page_size: 100, status: 'submitted' }).then(res => setSubmissions(res.items)).catch(console.error);
      userService.getUsers({ role: 'trainer', page_size: 100 }).then(res => setTrainers(res.items)).catch(console.error);
    }
  }, [isOpen]);

  useEffect(() => {
    if (editEvaluation) {
      setSubmissionId(String(editEvaluation.submission_id));
      setTrainerId(String(editEvaluation.trainer_id));
      setCodeQuality(editEvaluation.code_quality || 1);
      setFunctionality(editEvaluation.functionality || 1);
      setDocumentation(editEvaluation.documentation || 1);
      setTimeliness(editEvaluation.timeliness || 1);
      setFeedback(editEvaluation.feedback || '');
      setStrengths(editEvaluation.strengths || '');
      setImprovements(editEvaluation.improvements || '');
    } else {
      setSubmissionId(''); setTrainerId(''); setCodeQuality(1); setFunctionality(1); setDocumentation(1); setTimeliness(1);
      setFeedback(''); setStrengths(''); setImprovements('');
    }
    setErrors({});
  }, [editEvaluation, isOpen]);

  const validate = () => {
    const e: Record<string, string> = {};
    if (!submissionId) e.submission_id = 'Submission is required';
    if (!trainerId) e.trainer_id = 'Evaluator is required';
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const calculateScore = () => {
    return Math.round(((codeQuality + functionality + documentation + timeliness) / 40) * 100);
  };

  const handleSubmit = async (evt: React.FormEvent) => {
    evt.preventDefault();
    if (!validate()) return;
    
    setSubmitting(true);
    try {
      await onSubmit({
        submission_id: Number(submissionId),
        trainer_id: Number(trainerId),
        code_quality: codeQuality,
        functionality,
        documentation,
        timeliness,
        score: calculateScore(),
        feedback,
        strengths,
        improvements
      });
    } catch (err: any) {
      const errorData = err.response?.data?.error;
      const errorMessage = typeof errorData === 'object' && errorData !== null ? errorData.message : errorData || 'Failed to save evaluation';
      setErrors({ submit: errorMessage });
    } finally {
      setSubmitting(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-card" onClick={e => e.stopPropagation()} style={{ width: '600px', maxWidth: '90vw' }}>
        <div className="modal-header">
          <h3 className="modal-title">{editEvaluation ? 'Edit Evaluation' : 'New Evaluation'}</h3>
        </div>
        <form onSubmit={handleSubmit}>
          <div className="modal-body" style={{ maxHeight: '70vh', overflowY: 'auto' }}>
            {errors.submit && <div className="error-banner">{errors.submit}</div>}
            
            <div className="two-col">
              <div className="form-group">
                <label className="form-label">Submission</label>
                <select className={`form-input ${errors.submission_id ? 'error' : ''}`} value={submissionId} onChange={e => setSubmissionId(e.target.value)} disabled={!!editEvaluation}>
                  <option value="">Select Submission</option>
                  {submissions.map(s => <option key={s.id} value={s.id}>{s.task_title || `Submission #${s.id}`} ({s.intern_name})</option>)}
                </select>
                {errors.submission_id && <div className="form-error">{errors.submission_id}</div>}
              </div>

              <div className="form-group">
                <label className="form-label">Evaluator (Trainer)</label>
                <select className={`form-input ${errors.trainer_id ? 'error' : ''}`} value={trainerId} onChange={e => setTrainerId(e.target.value)}>
                  <option value="">Select Trainer</option>
                  {trainers.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                </select>
                {errors.trainer_id && <div className="form-error">{errors.trainer_id}</div>}
              </div>
            </div>

            <div className="form-group">
              <h4 style={{ margin: '15px 0 5px 0', fontSize: '14px', color: 'var(--text-main)' }}>Scores (1-10)</h4>
              <div className="two-col" style={{ gap: '10px' }}>
                <div>
                  <label className="form-label">Code Quality ({codeQuality})</label>
                  <input type="range" min="1" max="10" value={codeQuality} onChange={e => setCodeQuality(Number(e.target.value))} style={{ width: '100%' }} />
                </div>
                <div>
                  <label className="form-label">Functionality ({functionality})</label>
                  <input type="range" min="1" max="10" value={functionality} onChange={e => setFunctionality(Number(e.target.value))} style={{ width: '100%' }} />
                </div>
                <div>
                  <label className="form-label">Documentation ({documentation})</label>
                  <input type="range" min="1" max="10" value={documentation} onChange={e => setDocumentation(Number(e.target.value))} style={{ width: '100%' }} />
                </div>
                <div>
                  <label className="form-label">Timeliness ({timeliness})</label>
                  <input type="range" min="1" max="10" value={timeliness} onChange={e => setTimeliness(Number(e.target.value))} style={{ width: '100%' }} />
                </div>
              </div>
              <div style={{ textAlign: 'right', marginTop: '10px', fontSize: '1rem', fontWeight: 600 }}>
                Overall Score: <span style={{ color: 'var(--accent)', marginLeft: '8px', fontSize: '1.2rem' }}>{calculateScore()}%</span>
              </div>
            </div>

            <div className="form-group">
              <label className="form-label">Feedback Notes</label>
              <textarea className="form-input" style={{ minHeight: '80px', resize: 'vertical' }} value={feedback} onChange={e => setFeedback(e.target.value)} placeholder="General comments..." />
            </div>

            <div className="two-col">
              <div className="form-group">
                <label className="form-label">Key Strengths</label>
                <textarea className="form-input" style={{ minHeight: '60px', resize: 'vertical' }} value={strengths} onChange={e => setStrengths(e.target.value)} placeholder="e.g. Good variable naming" />
              </div>
              <div className="form-group">
                <label className="form-label">Areas for Improvement</label>
                <textarea className="form-input" style={{ minHeight: '60px', resize: 'vertical' }} value={improvements} onChange={e => setImprovements(e.target.value)} placeholder="e.g. Needs more comments" />
              </div>
            </div>
          </div>
