import React, { useEffect, useMemo, useState } from 'react';
import Badge from '@/components/Shared/Badge';
import { trainerService } from '@/services/trainerService';
import type { Submission } from '@/types';

interface TrainerSubmissionsProps {
  onNavigate: (screen: string) => void;
  onSelectSubmission: (submission: Submission) => void;
}

const statusOptions: Array<{ label: string; value: string }> = [
  { label: 'All', value: '' },
  { label: 'Pending', value: 'submitted' },
  { label: 'Reviewed', value: 'reviewed' },
  { label: 'Revision', value: 'revision_requested' },
];

const variantForStatus = (status: string) => {
  if (status === 'reviewed') return 'green';
  if (status === 'submitted' || status === 'pending') return 'yellow';
  if (status === 'revision_requested') return 'red';
  return 'gray';
};

const labelForStatus = (status: string) => {
  if (status === 'submitted' || status === 'pending') return 'Pending Review';
  if (status === 'reviewed') return 'Reviewed';
  if (status === 'revision_requested') return 'Revision Requested';
  return status;
};

const TrainerSubmissions: React.FC<TrainerSubmissionsProps> = ({ onNavigate, onSelectSubmission }) => {
  const [submissions, setSubmissions] = useState<Submission[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [status, setStatus] = useState('');
  const [updatingId, setUpdatingId] = useState<number | null>(null);

  const fetchSubmissions = async () => {
    setLoading(true);
    try {
      const data = await trainerService.getMySubmissions(status || undefined, search || undefined);
      setSubmissions(data);
    } catch {
      setSubmissions([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchSubmissions();
  }, [status]);

  // Client-side search filtering on top of server results
  const filtered = useMemo(() => {
    if (!search) return submissions;
    const q = search.toLowerCase();
    return submissions.filter(s => {
      const text = `${s.task_title ?? ''} ${s.intern_name ?? ''} ${s.notes ?? ''}`.toLowerCase();
      return text.includes(q);
    });
  }, [submissions, search]);

  const handleRequestRevision = async (submission: Submission) => {
    setUpdatingId(submission.id);
    try {
      await trainerService.updateSubmissionStatus(submission.id, 'revision_requested');
      // Refresh list
      await fetchSubmissions();
    } catch (err) {
      console.error('Failed to request revision', err);
      alert('Failed to request revision. Please try again.');
    } finally {
      setUpdatingId(null);
    }
  };

  return (
    <div className="view-container fade-in">
      <div className="page-header">
        <div>
          <h1 className="page-title">Submission Review</h1>
          <p className="page-subtitle">Review and evaluate intern submissions</p>
        </div>
      </div>

      <div className="search-row">
        <input
          type="text"
          className="search-input"
          placeholder="Search by task or intern name..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
        <div className="btn-group">
          {statusOptions.map((option) => (
            <button
              key={option.value}
              className={`filter-chip ${status === option.value ? 'active' : ''}`}
              onClick={() => setStatus(option.value)}
              type="button"
            >
              {option.label}
            </button>
          ))}
        </div>
      </div>

      <div className="admin-card">
        <div className="admin-card-body">
          {loading ? (
            <div className="loader-wrapper">
              <div className="loading-wave">
                <div className="loading-bar"></div>
                <div className="loading-bar"></div>
                <div className="loading-bar"></div>
                <div className="loading-bar"></div>
              </div>
            </div>
          ) : filtered.length === 0 ? (
            <div className="empty-state">No submissions match your filters.</div>
          ) : (
            <div className="submission-list">
              {filtered.map((submission) => (
                <div key={submission.id} className="submission-card">
                  <div className="submission-title">{submission.task_title}</div>
                  <div className="time-muted">
                    {submission.intern_name} · Submitted {new Date(submission.submitted_at).toLocaleString()}
                  </div>
                  {submission.notes && <p className="submission-copy">{submission.notes}</p>}
                  <div className="submission-meta">
                    <a href={submission.github_url} target="_blank" rel="noreferrer" className="link-button">
                      {submission.github_url}
                    </a>
                    <Badge variant={variantForStatus(submission.status)}>{labelForStatus(submission.status)}</Badge>
                  </div>
                  <div className="submission-actions">
                    {(submission.status === 'submitted' || submission.status === 'pending') && (
                      <>
                        <button
                          className="btn btn-primary btn-sm"
                          type="button"
                          onClick={() => {
                            onSelectSubmission(submission);
                            onNavigate('trainer-evaluation');
                          }}
                        >
                          Review & Score
                        </button>
                        <button
                          className="btn btn-secondary btn-sm"
                          type="button"
                          disabled={updatingId === submission.id}
                          onClick={() => handleRequestRevision(submission)}
                        >
                          {updatingId === submission.id ? 'Sending...' : 'Request Revision'}
                        </button>
                      </>
                    )}
                    {submission.status === 'reviewed' && (
                      <button
                        className="btn btn-secondary btn-sm"
                        type="button"
                        onClick={() => {
                          onSelectSubmission(submission);
                          onNavigate('trainer-evaluation');
                        }}
                      >
                        View Evaluation
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default TrainerSubmissions;

import React, { createContext, useState, useEffect, useContext, type ReactNode } from 'react';
import type { User } from '@/types';

interface AuthContextType {
  user: User | null;
  token: string | null;
  isAuthenticated: boolean;
  login: (user: User, token: string) => void;
  logout: () => void;
}

export const AuthContext = createContext<AuthContextType>({
  user: null,
  token: null,
  isAuthenticated: false,
  login: () => {},
  logout: () => {},
});

export const useAuth = () => useContext(AuthContext);

interface AuthProviderProps {
  children: ReactNode;
}

export const AuthProvider: React.FC<AuthProviderProps> = ({ children }) => {
  const [user, setUser] = useState<User | null>(() => {
    const stored = localStorage.getItem('user');
    return stored ? JSON.parse(stored) : null;
  });

  const [token, setToken] = useState<string | null>(() => {
    return localStorage.getItem('token');
  });

  const isAuthenticated = !!token && !!user;

  const login = (userData: User, authToken: string) => {
    setUser(userData);
    setToken(authToken);
    localStorage.setItem('user', JSON.stringify(userData));
    localStorage.setItem('token', authToken);
  };

  const logout = () => {
    setUser(null);
    setToken(null);
    localStorage.removeItem('user');
    localStorage.removeItem('token');
  };

  useEffect(() => {
    const handleStorage = (e: StorageEvent) => {
      if (e.key === 'token' && !e.newValue) {
        setUser(null);
        setToken(null);
      }
    };
    window.addEventListener('storage', handleStorage);
    return () => window.removeEventListener('storage', handleStorage);
  }, []);

  return (
    <AuthContext.Provider value={{ user, token, isAuthenticated, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

import React, { createContext, useState, useEffect, useContext, type ReactNode } from 'react';

type Theme = 'dark' | 'light';

interface ThemeContextType {
  theme: Theme;
  isDark: boolean;
  toggleTheme: () => void;
}

const ThemeContext = createContext<ThemeContextType>({
  theme: 'dark',
  isDark: true,
  toggleTheme: () => {},
});

export const useTheme = () => useContext(ThemeContext);

interface ThemeProviderProps {
  children: ReactNode;
}

export const ThemeProvider: React.FC<ThemeProviderProps> = ({ children }) => {
  const [theme, setTheme] = useState<Theme>(() => {
    return (localStorage.getItem('theme') as Theme) || 'dark';
  });

  const isDark = theme === 'dark';

  const toggleTheme = () => {
    setTheme((prev) => (prev === 'dark' ? 'light' : 'dark'));
  };

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme);
    localStorage.setItem('theme', theme);
  }, [theme]);

  return (
    <ThemeContext.Provider value={{ theme, isDark, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

import React, { useState } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";
import { useAuth } from "@/context/AuthContext";
import { useTheme } from "@/context/ThemeContext";
import api from '../services/api';
import "./LoginPanel.css";

const LoginPanel: React.FC = () => {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const { login } = useAuth();
  const { isDark, toggleTheme } = useTheme();
  const [form, setForm] = useState({ email: "", password: "" });
  const [error, setError] = useState<string>("");
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState<boolean>(false);
  const selectedRole = searchParams.get("role") || "";

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setError("");
  };

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!form.email || !form.password) {
      setError("All fields are required");
      return;
    }

    setLoading(true);
    try {
      const { data } = await api.post("/auth/login", form);
      const role = data.user?.role;

      // Validate that the user is logging into the correct panel
      if (selectedRole && role !== selectedRole) {
        setError(`Access denied. Please sign in via the ${role.charAt(0).toUpperCase() + role.slice(1)} Login panel.`);
        setLoading(false);
        return;
      }

      login(data.user, data.token);

      // Role-based navigation
      if (role === "admin") navigate("/admin");
      else if (role === "trainer") navigate("/trainer");
      else navigate("/intern");
    } catch (err: any) {
      setError(err.response?.data?.error?.message || "Invalid email or password");
      console.log(err);
    } finally {
      setLoading(false);
    }
  };

  const roleLabel = selectedRole
    ? selectedRole.charAt(0).toUpperCase() + selectedRole.slice(1)
    : "";

  return (
    <div className="login-page">
      {/* Theme Toggle Switch */}
      <div className="login-theme-toggle">
        <span className="toggle-icon">🌙</span>
        <label className="switch">
          <input
            type="checkbox"
            checked={!isDark}
            onChange={toggleTheme}
          />
          <span className="slider"></span>
        </label>
        <span className="toggle-icon">☀️</span>
      </div>

      <button className="back-button" onClick={() => navigate("/")} title="Go back">
        ← Back
      </button>

      <div className="login-card">
        {/* Branded Logo */}
        <div className="card-header">
          <h1 className="login-logo">
            <span className="logo-intern">Intern</span>
            <span className="logo-hub">Hub</span>
          </h1>
          <h2 className="login-title">
            {roleLabel ? `${roleLabel} Login` : "Login to continue"}
          </h2>
        </div>

        <form onSubmit={handleSubmit} className="login-form">
          <div className="form-group">
            <label htmlFor="login-email">Email</label>
            <input
              id="login-email"
              type="email"
              name="email"
              placeholder="Enter your email"
              value={form.email}
              onChange={handleChange}
              required
            />
          </div>

          <div className="form-group">
            <label htmlFor="login-password">Password</label>
            <div className="password-wrapper">
              <input
                id="login-password"
                type={showPassword ? "text" : "password"}
                name="password"
                placeholder="Enter your password"
                value={form.password}
                onChange={handleChange}
                required
              />
              <span onClick={() => setShowPassword(!showPassword)} className="password-toggle">
                {showPassword ? "Hide" : "Show"}
              </span>
            </div>
          </div>

          {error && <div className="error-message">{error}</div>}

          <button type="submit" className="login-btn" disabled={loading}>
            {loading ? "Signing in…" : "Sign In"}
          </button>
        </form>
      </div>
    </div>
  );
};

export default LoginPanel;

import api from './api';
import type { Evaluation, PaginatedResponse } from '@/types';

export interface EvaluationQueryParams {
  page?: number;
  page_size?: number;
  submission_id?: number;
  trainer_id?: number;
}

export const evaluationService = {
  getEvaluations: async (params?: EvaluationQueryParams): Promise<PaginatedResponse<Evaluation>> => {
    const res = await api.get('/evaluations', { params });
    return res.data;
  },

  createEvaluation: async (data: any): Promise<Evaluation> => {
    const res = await api.post('/evaluations', data);
    return res.data;
  },

  updateEvaluation: async (id: number, data: any): Promise<Evaluation> => {
    const res = await api.put(`/evaluations/${id}`, data);
    return res.data;
  },

  deleteEvaluation: async (id: number): Promise<void> => {
    await api.delete(`/evaluations/${id}`);
  }
};
